static int run_probe_vulnerable(const AgentConfig *cfg, const ProbeRequest *req) {
    if (req->target[0] == '-') {
        log_msg("ERROR", "invalid target");
        return -1;
    }
    for (const unsigned char *p = (const unsigned char *)req->target; *p; ++p) {
        if (!(isalnum(*p) || *p == '.' || *p == '-' || *p == ':')) {
            log_msg("ERROR", "invalid target");
            return -1;
        }
    }

    pid_t pid = fork();
    if (pid < 0) {
        perror("fork");
        return -1;
    }
    if (pid == 0) {
        char *argv_exec[] = {
            (char *)cfg->tool,
            (char *)cfg->arg1,
            (char *)cfg->arg2,
            (char *)req->target,
            NULL
        };
        execvp(cfg->tool, argv_exec);
        perror("execvp");
        _exit(127);
    }

    int status = 0;
    if (waitpid(pid, &status, 0) < 0) {
        perror("waitpid");
        return -1;
    }
    if (!WIFEXITED(status) || WEXITSTATUS(status) != 0) {
        log_msg("ERROR", "probe command failed");
        return -1;
    }
    return 0;
}
